body {
  line-height: 1;
}
#adunit {
  color: #373737;
  font: 14px "Helvetica Neue", Helvetica, Arial, sans-serif;
}
a {
  text-decoration: none;
  font-weight: bold;
  color: inherit;
}
a:hover, a:active {
  text-decoration: underline;
}
.advertiser {
  font-size: 12px;
  padding-bottom: .3em;
}
.attribution {
