  padding-bottom: .3em;
  word-wrap: break-word;
  clear: none;
  color: #222;
}
.title a {
  display: flex;
  padding-right: 18px;
  background: url(https://rocketnews24.com/wp-content/themes/rocketnews/img/mobile/pts_arrow.png) right center no-repeat;
}
.title a .thumbnail {
  width: 133px;
  height: 98px;
  background-image: url(https://tpc.googlesyndication.com/simgad/14678052087062615672?);
