  background-position: center center;
  margin-right: .5em;
}
.title a .text {
  flex: 1;
  font-weight: bold;
}
.meta {
  color: #666;
  clear: both;
  line-height: 18px;
  font-size: 12px;
}
.meta a {
  display: inline;
}
@media only screen and (max-device-width: 320px) {
  .title a .thumbnail {
    width: 95px;
    height: 70px;
  }
}
